// Portfolio Manager
class PortfolioManager {
    private var stocks: [String: Stock] = [:]
    
    func addStock(stock: Stock) {
        if let existingStock = stocks[stock.symbol] {
            stocks[stock.symbol]?.quantity += stock.quantity
        } else {
            stocks[stock.symbol] = stock
        }
    }
    
    func removeStock(symbol: String, quantity: Int) -> Bool {
        guard let existingStock = stocks[symbol], existingStock.quantity >= quantity else {
            return false
        }
        stocks[symbol]?.quantity -= quantity
        if stocks[symbol]?.quantity == 0 {
            stocks.removeValue(forKey: symbol)
        }
        return true
    }
    
    func listStocks() -> [Stock] {
        return Array(stocks.values)
    }
}

